(3, 1, 1, 0, NULL, NULL, 'Data Analyst', 'Analytics', 'TechNova Solutions', 'Chennai, India', 'Analyze business data, identify trends, and create reports for decision making.', 'Python, SQL, Excel, Power BI', '1-3 Years', 3, 80, 'REQUIRED_SOFT', 'open', '2026-03-06 17:14:15', 'Full-time', NULL, NULL),
(4, 1, 1, 0, NULL, NULL, 'HR Executive', 'Human Resources', 'TechNova Solutions', 'Kochi, India', 'Handle recruitment processes, employee engagement, and HR documentation.', 'Recruitment, Communication, HRMS, Interview Coordination', '1-2 Years', 1, 70, 'OPTIONAL', 'open', '2026-03-06 17:14:15', 'Full-time', NULL, NULL),
(5, 1, 1, 0, NULL, NULL, 'DevOps Engineer', 'IT / Cloud', 'TechNova Solutions', 'Bangalore, India', 'Manage CI/CD pipelines, cloud infrastructure, and deployment automation.', 'Docker, Kubernetes, AWS, CI/CD, Linux', '3-5 Years', 2, 85, 'REQUIRED_HARD', 'open', '2026-03-06 17:14:15', 'Full-time', NULL, NULL),
(6, 3, 2, 0, NULL, NULL, 'Backend Developer', 'IT / Software', 'PrecisionTech Industries', 'Bangalore, India', 'Develop and maintain server-side logic and APIs for scalable web applications.', 'PHP, Laravel, MySQL, JavaScript', '2-3 years', 1, 80, 'OPTIONAL', 'open', '2026-03-06 17:25:19', 'Full-time', '3 LPA', '2026-03-31'),
(7, 3, 2, 0, NULL, NULL, 'Electrical Engineer', 'Engineering', 'PrecisionTech Industries', 'Chennai, India', 'Design, develop, and maintain electrical systems for industrial applications.', 'Circuit Design, PLC, Electrical Testing, AutoCAD', '1-3 Years', 2, 78, 'REQUIRED_HARD', 'open', '2026-03-06 17:28:44', 'Full-time', NULL, NULL),
(8, 3, 2, 0, NULL, NULL, 'Digital Marketing Executive', 'Marketing', 'PrecisionTech Industries', 'Chennai, India', 'Plan and execute digital marketing campaigns including SEO, SEM, and social media.', 'SEO, Google Ads, Social Media Marketing, Content Marketing', '1-2 Years', 2, 70, 'OPTIONAL', 'open', '2026-03-06 17:28:44', 'Full-time', NULL, NULL),
(9, 3, 2, 0, NULL, NULL, 'UI/UX Designer', 'Design', 'PrecisionTech Industries', 'Chennai, India', 'Design intuitive user interfaces and improve user experience for web and mobile apps.', 'Figma, Adobe XD, Wireframing, Prototyping', '2-3 Years', 1, 75, 'OPTIONAL', 'open', '2026-03-06 17:28:44', 'Full-time', NULL, NULL),
